using Microsoft.AspNetCore.Authorization;using Microsoft.AspNetCore.Mvc.RazorPages;using Microsoft.EntityFrameworkCore;using ProjectManagement.Features.MediaLibrary.Data;using ProjectManagement.Features.MediaLibrary.Domain;
namespace ProjectManagement.Pages.Photos.People;[Authorize(Roles="Admin,HoD")] public sealed class IndexModel:PageModel{private readonly MediaLibraryDbContext _db;public IndexModel(MediaLibraryDbContext db)=>_db=db;public IReadOnlyList<PersonRow> People{get;private set;}=[];public async Task OnGetAsync(CancellationToken ct){People=await _db.Persons.AsNoTracking().Where(x=>x.Status==MediaPersonStatus.Confirmed&&!x.IsHidden).OrderBy(x=>x.DisplayName).Select(x=>new PersonRow(x.Id,x.DisplayName,x.FaceAssignments.Count(y=>y.RemovedAtUtc==null),x.RepresentativeFaceId)).ToListAsync(ct);}public sealed record PersonRow(Guid Id,string Name,int FaceCount,Guid? RepresentativeFaceId);}
